 function shouldRemoveRuntimeDepsLock(
-  owner: { pid?: number; createdAtMs?: number },
+  owner: Pick<RuntimeDepsLockOwner, "pid" | "createdAtMs" | "lockDirMtimeMs" | "ownerFileMtimeMs">,
   nowMs: number,
